import { Fn, If, PI, clamp, cos, cross, dot, equirectUV, float, log, max, mix, normalize, pow, reflect, sin, sqrt, struct, vec3 } from "./three_tsl.js";
//#region node_modules/three/examples/jsm/tsl/utils/SpecularHelpers.js
/**
* Specular / microfacet BRDF helpers: VNDF sampling, GTR distribution, Smith geometry,
* Fresnel, reflection importance sampling, parallax-corrected ray-length terms, and
* equirectangular environment sampling / MIS helpers.
* Pure TSL functions of their inputs (no scene/camera state).
*/
/**
* Sentinel ray length the SSR pass writes for environment misses (no screen-space hit), set far above
* any real hit distance so a single magnitude test separates misses from hits and survives `.max( 0 )`.
*
* @type {number}
*/
var ENV_RAY_LENGTH = 1e4;
/**
* Classification threshold for {@link ENV_RAY_LENGTH}: above this is an env miss, below a real hit.
* An order of magnitude under the sentinel, robust to fp16 storage and bilinear blending at borders.
*
* @type {number}
*/
var ENV_RAY_LENGTH_THRESHOLD = 1e3;
var SampleGGXVNDF = Fn(([V, ax, ay, r1, r2]) => {
	const wiStd = normalize(vec3(ax.mul(V.x), ay.mul(V.y), V.z)).toVar();
	const a = ax.min(ay).toVar();
	const s = float(1).add(V.xy.length()).toVar();
	const a2 = a.mul(a).toVar();
	const s2 = s.mul(s).toVar();
	const k = a2.oneMinus().mul(s2).div(s2.add(a2.mul(V.z).mul(V.z))).toVar();
	const b = wiStd.z.mul(k).toVar();
	const phi = float(6.283185307179586).mul(r1).toVar();
	const z = r2.oneMinus().mul(float(1).add(b)).sub(b).toVar();
	const sinTheta = sqrt(max(float(0), float(1).sub(z.mul(z)))).toVar();
	const wmStd = vec3(sinTheta.mul(cos(phi)), sinTheta.mul(sin(phi)), z).toVar().add(wiStd).toVar();
	return normalize(vec3(ax.mul(wmStd.x), ay.mul(wmStd.y), max(float(0), wmStd.z))).toVar();
}, {
	name: "SampleGGXVNDF",
	type: "vec3",
	inputs: [
		{
			name: "V",
			type: "vec3"
		},
		{
			name: "ax",
			type: "float"
		},
		{
			name: "ay",
			type: "float"
		},
		{
			name: "r1",
			type: "float"
		},
		{
			name: "r2",
			type: "float"
		}
	]
});
var D_GTR = Fn(([roughness, NoH, k]) => {
	const a2 = roughness.mul(roughness).toVar();
	const base = NoH.mul(NoH).toVar().mul(a2.sub(float(1))).add(float(1)).toVar();
	return a2.div(PI.mul(pow(base, k))).toVar();
});
var SmithG = Fn(([NDotX, alpha]) => {
	const a2 = alpha.mul(alpha).toVar();
	const NDotX2 = NDotX.mul(NDotX).toVar();
	return float(2).mul(NDotX).div(NDotX.add(sqrt(a2.add(a2.oneMinus().mul(NDotX2)))));
});
var GeometryTerm = Fn(([NoL, NoV, alphaG]) => {
	const G1v = SmithG(NoV, alphaG).toVar();
	const G1l = SmithG(NoL, alphaG).toVar();
	return G1v.mul(G1l).toVar();
});
var GGXVNDFPdf = Fn(([NoH, NoV, roughness]) => {
	const D = D_GTR(roughness, NoH, float(2)).toVar();
	const a2 = roughness.mul(roughness).toVar();
	const sinV2 = max(float(0), float(1).sub(NoV.mul(NoV))).toVar();
	const s = float(1).add(sqrt(sinV2)).toVar();
	const s2 = s.mul(s).toVar();
	const k = float(1).sub(a2).mul(s2).div(s2.add(a2.mul(NoV).mul(NoV))).toVar();
	const t = sqrt(a2.mul(sinV2).add(NoV.mul(NoV))).toVar();
	return D.div(max(float(1e-6), float(2).mul(k.mul(NoV).add(t)))).toVar();
});
/**
* Fresnel reflectance for the Schlick approximation.
*/
var F_Schlick = Fn(([f0, theta]) => {
	const oneMinus = float(1).sub(theta).toVar();
	const oneMinus2 = oneMinus.mul(oneMinus).toVar();
	const oneMinus5 = oneMinus2.mul(oneMinus2).mul(oneMinus).toVar();
	return f0.add(vec3(1).sub(f0).mul(oneMinus5)).toVar();
});
/**
* Specular dominant factor for parallax-corrected ray length.
* From REBLUR: A Hierarchical Recurrent Denoiser (NRD).
*/
var getSpecularDominantFactor = Fn(([NoV, roughness]) => {
	const a = float(.298475).mul(log(float(39.4115).sub(float(39.0029).mul(roughness))));
	return clamp(float(1).sub(NoV).pow(10.8649).mul(float(1).sub(a)).add(a));
}).setLayout({
	name: "getSpecularDominantFactor",
	type: "float",
	inputs: [{
		name: "NoV",
		type: "float"
	}, {
		name: "roughness",
		type: "float"
	}]
});
/**
* Everything a single GGX reflection sample produces. `reflectDir` and `sampleWeight`
* drive the SSR ray-march and compositing; `pdf`, `NdotV`, `alpha` and `f0` are the GGX
* terms the env-miss MIS fallback needs so the caller never re-derives microfacet math.
*/
var ggxReflectionStruct = struct({
	reflectDir: "vec3",
	sampleWeight: "vec3",
	pdf: "float",
	NdotV: "float",
	alpha: "float",
	f0: "vec3"
});
/**
* Importance-samples the GGX/VNDF specular lobe for one pixel and returns the reflected
* ray direction plus the Monte-Carlo weight to apply to the gathered radiance, along with
* the GGX terms the SSR env-miss MIS fallback needs.
*
* @param {Node<vec3>} N - View-space shading normal (normalized).
* @param {Node<vec3>} V - View-space surface→camera direction (normalized).
* @param {Node<float>} roughness - Perceptual roughness in `[0,1]`.
* @param {Node<float>} metalness - Metalness in `[0,1]`.
* @param {Node<vec3>} albedo - Surface base color; tints the metal Fresnel reflectance (`f0`).
* @param {Node<vec4>} Xi - Per-pixel random numbers; only `.xy` are used.
* @return {ggxReflectionStruct}
*/
var ggxReflectionSample = Fn(([N, V, roughness, metalness, albedo, Xi]) => {
	const a = roughness.mul(roughness).max(.001).toVar();
	const ax = a.toVar();
	const ay = a.toVar();
	let T = cross(vec3(0, 0, 1), N).toVar();
	T = T.normalize().toVar();
	If(T.length().lessThan(.001), () => {
		T.assign(cross(vec3(0, 1, 0), N).normalize());
	});
	const B = cross(N, T).normalize().toVar();
	const Hlocal = SampleGGXVNDF(vec3(dot(T, V), dot(B, V), dot(N, V)).toVar(), ax, ay, Xi.x, Xi.y).toVar();
	If(Hlocal.z.lessThan(0), () => {
		Hlocal.assign(Hlocal.negate());
	});
	const h = normalize(T.mul(Hlocal.x).add(B.mul(Hlocal.y)).add(N.mul(Hlocal.z))).toVar();
	const viewReflectDir = reflect(V.negate(), h).normalize().toVar();
	const L = viewReflectDir.toVar();
	const H = normalize(V.add(L)).toVar();
	const NdotV = max(float(0), dot(N, V)).toVar();
	const NdotL = max(float(0), dot(N, L)).toVar();
	const NdotH = max(float(0), dot(N, H)).toVar();
	const VdotH = max(float(0), dot(V, H)).toVar();
	const f0 = mix(vec3(.04), albedo, metalness).toVar();
	const fresnelWeight = F_Schlick(f0, VdotH).toVar();
	const pdf = GGXVNDFPdf(NdotH, NdotV, ax).toVar();
	const a2 = ax.mul(ax).toVar();
	const sinV2 = NdotV.mul(NdotV).oneMinus().max(0).toVar();
	const sB = float(1).add(sqrt(sinV2)).toVar();
	const s2B = sB.mul(sB).toVar();
	const kB = a2.oneMinus().mul(s2B).div(s2B.add(a2.mul(NdotV).mul(NdotV))).toVar();
	const tB = sqrt(a2.mul(sinV2).add(NdotV.mul(NdotV))).toVar();
	return ggxReflectionStruct(viewReflectDir, fresnelWeight.mul(GeometryTerm(NdotL, NdotV, ax)).mul(kB.mul(NdotV).add(tB)).div(float(2).mul(NdotV).max(1e-4)).toVar(), pdf, NdotV, ax, f0);
});
Fn(([uvIn]) => {
	const phi = uvIn.x.mul(Math.PI * 2).sub(Math.PI);
	const lat = uvIn.y.sub(.5).mul(Math.PI);
	const cosLat = cos(lat);
	return normalize(vec3(cosLat.mul(cos(phi)), sin(lat), cosLat.mul(sin(phi))));
}).setLayout({
	name: "equirectUvToDir",
	type: "vec3",
	inputs: [{
		name: "uv",
		type: "vec2"
	}]
});
var equirectDirPdf = Fn(([direction]) => {
	const sinTheta = sin(equirectUV(direction).y.mul(Math.PI));
	return sinTheta.abs().lessThan(float(1e-6)).select(float(0), float(1).div(float(2 * Math.PI * Math.PI).mul(sinTheta)));
}).setLayout({
	name: "equirectDirPdf",
	type: "float",
	inputs: [{
		name: "direction",
		type: "vec3"
	}]
});
/**
* MIS power heuristic with β = 2: `pdfA² / (pdfA² + pdfB²)`.
* Weights the contribution of the strategy that produced `pdfA` against the other strategy.
*
* @see Eric Veach, *Optimally Combining Sampling Techniques for Monte Carlo Rendering*
* @tsl
*/
var misPowerHeuristic = Fn(([pdfA, pdfB]) => {
	const pdfASq = pdfA.mul(pdfA);
	const pdfBSq = pdfB.mul(pdfB);
	return pdfASq.div(pdfASq.add(pdfBSq));
}).setLayout({
	name: "misPowerHeuristic",
	type: "float",
	inputs: [{
		name: "pdfA",
		type: "float"
	}, {
		name: "pdfB",
		type: "float"
	}]
});
//#endregion
export { GeometryTerm as a, getSpecularDominantFactor as c, F_Schlick as i, ggxReflectionSample as l, ENV_RAY_LENGTH as n, SmithG as o, ENV_RAY_LENGTH_THRESHOLD as r, equirectDirPdf as s, D_GTR as t, misPowerHeuristic as u };
